const transformations = [
  {
    label: "Repeatable quality",
    from: "From quality living in individual people's heads...",
    to: "To a shared, repeatable system that turns your best hires into the standard.",
  },
  {
    label: "Visibility & control",
    from: "From managing by gut feel and one-off check-ins...",
    to: "To real visibility into what's working, what's stuck, and what drives outcomes.",
  },
  {
    label: "Compounding productivity",
    from: "From reinventing the process every single time...",
    to: "To a partner that gets smarter about your business over time.",
  },
];

const testimonials = [
  {
    stat: "3x faster",
    label: "time-to-fill vs. industry average",
    quote:
      "Before Inprava, we were juggling three different agencies and still couldn't fill roles fast enough. Now everything runs through one team and it just works.",
    name: "Sarah Mitchell",
    role: "Head of People, TechCorp",
  },
  {
    stat: "48 hours",
    label: "average VA onboarding time",
    quote:
      "Our VA was up and running in two days. She handles everything — scheduling, research, inbox. I've genuinely gotten my evenings back.",
    name: "Rohan Mehta",
    role: "Founder, ScaleOps",
  },
  {
    stat: "98%",
    label: "client retention rate",
    quote:
      "One of our recent hires made an impact in the first 30 days. Inprava understood exactly what we needed without us having to over-explain.",
    name: "James O'Brien",
    role: "CTO, NovaBuild",
  },
];

export default function WhyInprava() {
  return (
    <>
      {/* From → To section */}
      <section id="results" className="bg-white py-24">
        <div className="max-w-5xl mx-auto px-8">
          <h2 className="text-4xl font-extrabold text-slate-900 mb-4">
            Make <em>every</em> hire your best hire
          </h2>
          <p className="text-slate-500 text-lg mb-12">
            Results that make you say "Let's do it again. And again. And
            again..."
          </p>
          <div className="flex flex-col gap-4">
            {transformations.map((t) => (
              <div
                key={t.label}
                className="grid grid-cols-1 md:grid-cols-3 gap-4 items-center bg-slate-50 rounded-2xl p-6 border border-slate-100"
              >
                <div>
                  <p className="text-xs font-semibold uppercase tracking-widest text-teal-500 mb-1">
                    {t.label}
                  </p>
                  <p className="text-sm text-slate-400">{t.from}</p>
                </div>
                <div className="text-center text-2xl text-slate-300 hidden md:block">
                  →
                </div>
                <div>
                  <p className="text-sm font-semibold text-slate-900">{t.to}</p>
                </div>
              </div>
            ))}
          </div>
        </div>
      </section>

      {/* Testimonials */}
      <section className="bg-slate-50 py-24">
        <div className="max-w-5xl mx-auto px-8">
          <p className="text-xs font-semibold uppercase tracking-widest text-slate-400 mb-4">
            client results
          </p>
          <h2 className="text-4xl font-extrabold text-slate-900 mb-4">
            Clients love Inprava — and they have their reasons
          </h2>
          <p className="text-slate-500 text-lg mb-12">
            "Users" and "raving fans" tend to be one and the same around here.
          </p>
          <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
            {testimonials.map((t) => (
              <div
                key={t.name}
                className="bg-white rounded-2xl border border-slate-100 p-7 flex flex-col gap-4"
              >
                <div>
                  <p className="text-4xl font-extrabold text-slate-900">
                    {t.stat}
                  </p>
                  <p className="text-sm text-slate-400 mt-1">{t.label}</p>
                </div>
                <p className="text-slate-600 text-sm leading-relaxed flex-1 italic">
                  "{t.quote}"
                </p>
                <div className="border-t border-slate-100 pt-4">
                  <p className="text-sm font-bold text-slate-900">{t.name}</p>
                  <p className="text-xs text-slate-400">{t.role}</p>
                </div>
              </div>
            ))}
          </div>
        </div>
      </section>

      {/* Logo marquee */}
      <section className="bg-white py-12 border-t border-b border-slate-100 overflow-hidden">
        <div className="flex animate-marquee whitespace-nowrap">
          {[...Array(2)].map((_, i) => (
            <div key={i} className="flex items-center gap-16 mx-8">
              {[
                "TechVentures",
                "NovaBuild",
                "ScaleOps",
                "Meridian",
                "ArcSystems",
                "PeakHire",
                "VentureCore",
                "SwiftOps",
                "BuildRight",
                "TalentFirst",
              ].map((name) => (
                <span
                  key={name}
                  className="text-slate-300 font-bold text-lg tracking-tight"
                >
                  {name}
                </span>
              ))}
            </div>
          ))}
        </div>
      </section>

      {/* Beliefs section */}
      <section className="bg-white py-24">
        <div className="max-w-5xl mx-auto px-8">
          <p className="text-xs font-semibold uppercase tracking-widest text-slate-400 mb-6">
            Four beliefs that guide our <em>team</em>, our <em>services</em>,
            and our <em>clients</em>
          </p>
          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
            {[
              {
                title: "Growing companies should have it all",
                body: "You shouldn't have to choose between quality and speed. With the right partner, you get both.",
              },
              {
                title: "It shouldn't take 5 vendors to scale 1 team",
                body: "We reject the fragmented status quo — one partner for hiring, VAs, and development means less coordination and more output.",
              },
              {
                title: "Relationships over transactions",
                body: "We measure success by how long our clients stay, not how quickly we close a deal. Your growth is our growth.",
              },
              {
                title: "Repeatable process = repeatable quality",
                body: "Your workflow is your competitive advantage. Without the right process, even the best talent will underperform.",
              },
            ].map((b) => (
              <div
                key={b.title}
                className="bg-slate-50 rounded-2xl border border-slate-100 p-7"
              >
                <h3 className="font-extrabold text-lg text-slate-900 mb-2">
                  {b.title}
                </h3>
                <p className="text-slate-500 text-sm leading-relaxed">
                  {b.body}
                </p>
              </div>
            ))}
          </div>
        </div>
      </section>
    </>
  );
}
